//! A self-describing reference for the card-effect DSL (the `[[abilities]]` /
//! `[[activated]]` / `[[statics]]` grammar authored in `cards/<set>/*.toml`).
//!
//! This is the single source for the human/AI-facing syntax doc
//! (`docs/dsl/EFFECT_DSL.md`, generated by the `dsl_reference` binary). It is kept
//! honest by `tests/dsl_reference.rs`, which checks that:
//!   - the committed doc equals [`reference_markdown`] (no drift),
//!   - every effect-verb example below actually parses (no stale syntax), and
//!   - every verb / trigger / restriction / scope the parser recognises is listed.
//!
//! When you add or change DSL syntax, update the tables here and regenerate the
//! doc (`cargo run --bin dsl_reference`).

/// One documented DSL element: a token/verb, a one-line description, and a TOML
/// `example` that must parse (for verbs the example is the `do` effect table).
#[derive(Debug, Clone, Copy)]
pub struct Entry {
    /// The token or verb name.
    pub name: &'static str,
    /// What it does (one line).
    pub about: &'static str,
    /// A parseable example — for an effect verb, the `do = <example>` table.
    pub example: &'static str,
}

/// Effect verbs usable inside a `do = { … }` (or an item of a `do = [ … ]`
