fn table(rows: &[(&str, &str)]) -> String {
    use std::fmt::Write;
    let mut s = String::from("| Token | Meaning |\n| --- | --- |\n");
    for (k, v) in rows {
        let _ = writeln!(s, "| `{k}` | {v} |");
    }
    s
}

/// The ability-table structure sections (triggered / activated / static / §7.7).
fn structures_md() -> String {
    let mut s = String::new();
    s.push_str("## Triggered abilities — `[[abilities]]`\n\n");
    s.push_str(
        "`on` selects the trigger; `do` is one effect table or an array (resolved in \
         order); `may = true` makes it \"you may\"; `during_your_turn` / \
         `during_opponents_turn` gate when it fires.\n\n",
    );
    s.push_str(
        "```toml\n[[abilities]]\non = \"play\"\ndo = [{ draw = 1 }, { gain_lore = 1 }]\n```\n\n",
    );
    s.push_str("### Triggers (`on`)\n\n");
    s.push_str(&table(&triggers()));
    s.push('\n');

    s.push_str("## Activated abilities — `[[activated]]`\n\n");
    s.push_str("A `cost` (`{ exert = true, ink = 1, banish = false }`) plus a `do` effect.\n\n");
    s.push_str(
        "```toml\n[[activated]]\ncost = { exert = true, ink = 1 }\ndo = { draw = 1 }\n```\n\n",
    );

    s.push_str("## Static abilities — `[[statics]]`\n\n");
    s.push_str(
        "A continuous stat modifier: one of `strength` / `willpower` / `lore` on a `to` \
         selector, optionally scaled (`per = \"<filter>\"`) or gated (`while = \"exerted\"`).\n\n",
    );
    s.push_str("```toml\n[[statics]]\nstrength = 1\nto = \"your other Hero characters\"\n```\n\n");

    s.push_str("## §7.7 replacements\n\n");
    s.push_str(
        "`[[redirect_damage]]` (`from = \"<selector>\"`) redirects matching damage onto \
         this card; `[[prevent_damage]]` (`to = \"<selector>\"`, `\"this\"` for itself) \
         prevents it.\n\n",
    );
    s
}

/// The vocabulary tables (verbs / selectors / amounts / scopes / durations / restrictions).
fn vocab_md() -> String {
    use std::fmt::Write;
    let mut s = String::new();
    s.push_str("## Effect verbs (`do`)\n\n");
    s.push_str("| Verb | Meaning | Example |\n| --- | --- | --- |\n");
    for e in effect_verbs() {
        let _ = writeln!(s, "| `{}` | {} | `{}` |", e.name, e.about, e.example);
    }
    s.push_str("\n## Target selectors (`target` / `to` / `from`)\n\n");
    s.push_str(&table(&selectors()));
    s.push_str("\nA leaf may also be the structured AST form (a TOML table) when the compact grammar can't express it.\n\n");
    s.push_str("## Amounts (any numeric field)\n\n");
    s.push_str(&table(&amounts()));
    s.push_str("\n## Player scopes (`who` / `whose`)\n\n");
    s.push_str(&table(&scopes()));
    s.push_str("\n## Durations (`duration`)\n\n");
    s.push_str(&table(&durations()));
    s.push_str("\n## Restrictions (`restrict`)\n\n");
    s.push_str(&table(&restrictions()));
    s
}

/// Render the full DSL reference as Markdown (the committed `docs/dsl/EFFECT_DSL.md`).
#[must_use]
pub fn reference_markdown() -> String {
    let mut s = String::new();
    s.push_str("# Effect DSL reference\n\n");
    s.push_str(
        "GENERATED — do not edit by hand. Run `cargo run --bin dsl_reference` to \
         regenerate from `src/domain/cards/dsl_reference.rs`. This is the authoritative \
         syntax for authoring card abilities in the per-card files \
         (`cards/<set>/<collector>.toml`); the grammar lives in \
         `src/domain/cards/dsl.rs`.\n\n",
    );
    s.push_str(
        "Abilities are authored at the top level of a per-card file; \
         `combine_sets.py` re-nests them under `card.` for the loader.\n\n",
    );
    s.push_str(&structures_md());
    s.push_str(&vocab_md());
    s
}
